// ── HELPERS ──────────────────────────────────────────────────────────────────
function parseCode(code) {
  const c = code.toUpperCase().trim();
  const spaceMatch = c.match(/^(.+?)\s+([A-Z0-9].*)$/);
  if (spaceMatch) return { base: spaceMatch[1], sep: " ", variant: spaceMatch[2] };
  const attachedMatch = c.match(/^([A-Z]*\d+)([A-Z]{2,})$/);
  if (attachedMatch) return { base: attachedMatch[1], sep: "", variant: attachedMatch[2] };
  return { base: c, sep: " ", variant: "" };
}

const STATUS = {
  exists:    { label:"YA EXISTE",              color:"#f87171", bg:"#1e0f0f", border:"#5c1f1f" },
  session:   { label:"REGISTRADO ESTA SESIÓN", color:"#fbbf24", bg:"#1a1400", border:"#54400a" },
  available: { label:"DISPONIBLE",             color:"#4ade80", bg:"#0b1a0f", border:"#1a5c30" },
  partial:   { label:"COINCIDENCIAS",          color:"#94a3b8", bg:"#181818", border:"#2e2e2e" },
};

let sessionGenerated = new Set();

export default function App() {
  // ── MARCA ACTIVA ──────────────────────────────────────────────────────────
  const [activeBrand, setActiveBrand] = useState("221");
  const [brandSearch, setBrandSearch] = useState("");

  // derived from activeBrand
  const brandData   = ALL_BRANDS[activeBrand] || { codes: [], names: {} };
  const CODES       = brandData.codes;
  const NAMES       = brandData.names;
  const PREFIX      = activeBrand;
  const codesSet    = useMemo(() => new Set(CODES.map(c => c.toUpperCase().trim())), [CODES]);

  const isAvailable = useCallback((code) => {
    const u = code.toUpperCase().trim();
    return !codesSet.has(u) && !sessionGenerated.has(u);
  }, [codesSet]);

  const checkCode = useCallback((code) => {
    const u = code.toUpperCase().trim();
    if (codesSet.has(u)) return "exists";
    if (sessionGenerated.has(u)) return "session";
    return "available";
  }, [codesSet]);

  const getName = useCallback((code) => {
    const u = code.toUpperCase().trim();
    return NAMES[u] || NAMES[code.trim()] || null;
  }, [NAMES]);

  const generateAlternatives = useCallback((code) => {
    const c = code.toUpperCase().trim();
    const results = [];
    const numRegex = /(\d+)/g;
    let match;
    const groups = [];
    while ((match = numRegex.exec(c)) !== null) {
      groups.push({ value: parseInt(match[1], 10), index: match.index, raw: match[1] });
    }
    if (groups.length === 0) return { results: [], siblings: [], parsed: { base: c, sep: "", variant: "" } };
    const tried = new Set();
    for (let g = groups.length - 1; g >= 0; g--) {
      const grp = groups[g];
      let found = 0;
      for (let delta = 1; delta <= 50 && found < 3; delta++) {
        const nextNum = grp.value + delta;
        const padded = grp.raw.startsWith("0") && grp.raw.length > 1
          ? String(nextNum).padStart(grp.raw.length, "0") : String(nextNum);
        const candidate = c.slice(0, grp.index) + padded + c.slice(grp.index + grp.raw.length);
        if (!tried.has(candidate) && isAvailable(candidate)) {
          tried.add(candidate);
          const segLabel = c.slice(0, grp.index) + `[${grp.raw}→${padded}]` + c.slice(grp.index + grp.raw.length);
          results.push({ code: candidate, type: "number", reason: segLabel });
          found++;
        }
      }
      if (results.length >= 6) break;
    }
    const { base } = parseCode(c);
    const siblings = CODES.filter(ec => { const p = parseCode(ec); return p.base === base && ec.toUpperCase() !== c; }).slice(0, 6);
    return { results: results.slice(0, 6), siblings, parsed: parseCode(c) };
  }, [CODES, isAvailable]);

  // ── UI STATE ──────────────────────────────────────────────────────────────
  const [tab, setTab] = useState("check");
  const [mode, setMode] = useState("verify");
  const [inputCode, setInputCode] = useState("");
  const [checkResult, setCheckResult] = useState(null);
  const [alternatives, setAlternatives] = useState(null);
  const [newCodes, setNewCodes] = useState([]);
  const [toast, setToast] = useState(null);
  const [genBase, setGenBase] = useState("");
  const [genResult, setGenResult] = useState(null);
  const [nameQuery, setNameQuery] = useState("");
  const [nameMatches, setNameMatches] = useState(null);
  const [selectedFamily, setSelectedFamily] = useState(null);
  const [colorSuffix, setColorSuffix] = useState("");
  const [genStep, setGenStep] = useState(1);
  const [searchTerm, setSearchTerm] = useState("");

  const showToast = (msg) => { setToast(msg); setTimeout(() => setToast(null), 2400); };

  const resetAll = () => {
    setCheckResult(null); setAlternatives(null);
    setGenResult(null); setInputCode(""); setGenBase("");
    setNameQuery(""); setNameMatches(null);
    setSelectedFamily(null); setColorSuffix(""); setGenStep(1);
  };

  // ── HANDLERS ─────────────────────────────────────────────────────────────
  const handleCheck = () => {
    const input = inputCode.trim().toUpperCase();
    if (!input) return;
    const exactStatus = checkCode(input);
    if (exactStatus !== "available") {
      setCheckResult({ code: input, status: exactStatus, matches: null });
      setAlternatives(generateAlternatives(input));
    } else {
      const matches = CODES.filter(c => c.toUpperCase().includes(input));
      if (matches.length > 0 && matches.length < CODES.length) {
        setCheckResult({ code: input, status: "partial", matches });
        setAlternatives(null);
      } else {
        setCheckResult({ code: input, status: "available", matches: null });
        setAlternatives(null);
      }
    }
  };

  const handleRegister = (code) => {
    const u = code.toUpperCase().trim();
    sessionGenerated.add(u);
    setNewCodes(prev => [...prev, { code: u, prefix: PREFIX, full: `${PREFIX}-${u}` }]);
    showToast(`✓ Registrado: ${PREFIX}-${u}`);
    setCheckResult(null); setAlternatives(null); setInputCode("");
  };

  const handleGenerate = () => {
    const base = genBase.trim().toUpperCase();
    if (!base) return;
    const result = generateAlternatives(base);
    setGenResult({ base, ...result });
  };

  const searchByName = () => {
    const q = nameQuery.trim().toUpperCase();
    if (!q) return;
    const words = q.split(/\s+/).filter(Boolean);
    const scored = Object.entries(NAMES)
      .map(([code, name]) => {
        const uname = name.toUpperCase();
        const score = words.filter(w => uname.includes(w)).length;
        return { code, name, score };
      })
      .filter(x => x.score > 0)
      .sort((a, b) => b.score - a.score)
      .slice(0, 20);
    setNameMatches(scored);
    setSelectedFamily(null); setColorSuffix(""); setGenStep(2);
  };

  const pickFamily = (code) => {
    const parsed = parseCode(code);
    const base = parsed.base;
    const sibs = CODES.filter(ec => { const p = parseCode(ec); return p.base === base; });
    setSelectedFamily({ base, code, siblings: sibs });
    setGenStep(3); setGenResult(null); setColorSuffix("");
  };

  const buildAndGenerate = () => {
    if (!selectedFamily) return;
    const suffix = colorSuffix.trim().toUpperCase();
    const baseWithColor = suffix ? selectedFamily.base + " " + suffix : selectedFamily.base;
    const result = generateAlternatives(baseWithColor);
    setGenBase(baseWithColor);
    setGenResult({ base: baseWithColor, ...result });
  };

  const filteredCodes = useMemo(() => {
    if (!searchTerm) return CODES.slice(0, 80);
    const q = searchTerm.toLowerCase();
    return CODES.filter(c => {
      const name = (NAMES[c] || NAMES[c.toUpperCase()] || "").toLowerCase();
      return name.includes(q) || c.toLowerCase().includes(q);
    });
  }, [searchTerm, CODES, NAMES]);

  // ── BRAND SELECTOR ───────────────────────────────────────────────────────
  const allBrandsSorted = useMemo(() => {
    return Object.entries(ALL_BRANDS)
      .sort((a, b) => b[1].codes.length - a[1].codes.length);
  }, []);

  const filteredBrands = useMemo(() => {
    if (!brandSearch.trim()) return allBrandsSorted;
    const q = brandSearch.trim();
    return allBrandsSorted.filter(([prefix]) => prefix.includes(q));
  }, [brandSearch, allBrandsSorted]);

  // ── RENDER ────────────────────────────────────────────────────────────────
  const S = { // shared styles
    card:    { background:"#1a1a1a", border:"1px solid #2a2a2a", borderRadius:10, padding:20, marginBottom:14 },
    label:   { fontSize:10, letterSpacing:3, color:"#888", marginBottom:7, display:"block" },
    input:   { width:"100%", background:"#111", border:"1px solid #333", borderRadius:7, padding:"10px 12px",
               color:"#e8e8e8", fontSize:13, fontFamily:"'Inter',sans-serif", outline:"none", boxSizing:"border-box" },
    btn:     { padding:"10px 20px", background:"#e8e8e8", color:"#111", border:"none", borderRadius:7,
               cursor:"pointer", fontSize:12, fontWeight:700, fontFamily:"'Inter',sans-serif" },
    btnGhost:{ padding:"10px 20px", background:"transparent", color:"#888", border:"1px solid #2a2a2a",
               borderRadius:7, cursor:"pointer", fontSize:12, fontFamily:"'Inter',sans-serif" },
  };

  return (
    <div style={{ minHeight:"100vh", background:"#111111", color:"#e8e8e8", fontFamily:"'Inter',sans-serif" }}>

      {/* ── HEADER ── */}
      <div style={{ background:"#141414", borderBottom:"1px solid #2a2a2a", padding:"22px 28px 0" }}>
        <div style={{ maxWidth:860, margin:"0 auto" }}>
          <div style={{ fontSize:10, letterSpacing:4, color:"#555", marginBottom:3 }}>SISTEMA DE GESTIÓN · PREFIJO {PREFIX}</div>
          <div style={{ display:"flex", alignItems:"baseline", gap:10, marginBottom:3 }}>
            <h1 style={{ fontSize:22, fontWeight:700, margin:0, color:"#fff" }}>Generador de Códigos</h1>
            <span style={{ fontSize:22, fontWeight:700, color:"#e0e0e0" }}>{PREFIX}</span>
          </div>
          <p style={{ margin:"0 0 18px", color:"#666", fontSize:11 }}>
            {CODES.length} artículos en marca {PREFIX} · {newCodes.length} nuevos esta sesión · {Object.keys(ALL_BRANDS).length} marcas cargadas
          </p>
          <div style={{ display:"flex", gap:0 }}>
            {[
              { id:"check",  label:"Verificar / Crear" },
              { id:"search", label:"Buscar artículos" },
              { id:"brands", label:`Marcas (${Object.keys(ALL_BRANDS).length})` },
              { id:"list",   label:`Sesión (${newCodes.length})` },
            ].map(t => (
              <button key={t.id} onClick={() => setTab(t.id)} style={{
                padding:"8px 18px", background: tab===t.id ? "#e8e8e8" : "transparent",
                color: tab===t.id ? "#111" : "#555", border:"none",
                borderBottom: tab===t.id ? "2px solid #e8e8e8" : "2px solid transparent",
                cursor:"pointer", fontSize:12, fontFamily:"'Inter',sans-serif",
                borderRadius: tab===t.id ? "4px 4px 0 0" : 0, transition:"all .2s",
              }}>{t.label}</button>
            ))}
          </div>
        </div>
      </div>

      <div style={{ maxWidth:860, margin:"0 auto", padding:"26px 28px" }}>

        {/* ── VERIFICAR / CREAR ── */}
        {tab === "check" && (<>
          <div style={{ display:"flex", gap:6, marginBottom:14 }}>
            {[["verify","🔍 Verificar código"],["generate","✨ Generar código nuevo"]].map(([m,label]) => (
              <button key={m} onClick={() => { setMode(m); resetAll(); }}
                style={{ padding:"8px 18px", background: mode===m ? "#e8e8e8" : "#1a1a1a",
                  color: mode===m ? "#111" : "#666", border:`1px solid ${mode===m ? "#e8e8e8" : "#2a2a2a"}`,
                  borderRadius:8, cursor:"pointer", fontSize:12, fontFamily:"'Inter',sans-serif",
                  fontWeight: mode===m ? 700 : 400, transition:"all .2s" }}>
                {label}
              </button>
            ))}
          </div>

          {/* VERIFY MODE */}
          {mode === "verify" && (
          <div style={S.card}>
            <span style={S.label}>CÓDIGO DEL ARTÍCULO (sin "{PREFIX}-")</span>
            <div style={{ display:"flex", gap:8 }}>
              <div style={{ background:"#111", border:"1px solid #2a2a2a", borderRadius:7, padding:"10px 12px",
                color:"#666", fontSize:14, display:"flex", alignItems:"center", whiteSpace:"nowrap" }}>
                {PREFIX}-
              </div>
              <input value={inputCode} onChange={e => setInputCode(e.target.value)}
                onKeyDown={e => e.key==="Enter" && handleCheck()}
                placeholder="Ej: M1103C NGR" autoFocus
                style={{ ...S.input }} />
              <button onClick={handleCheck} style={S.btn}>Verificar</button>
            </div>
          </div>)}

          {/* RESULT */}
          {checkResult && (() => {
            const st = STATUS[checkResult.status];
            return (
              <div style={{ background:st.bg, border:`1px solid ${st.border}`, borderRadius:10, padding:20, marginBottom:14 }}>
                <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", flexWrap:"wrap", gap:10 }}>
                  <div>
                    <div style={{ fontWeight:700, fontSize:18, color:"#e8e8e8", marginBottom:4 }}>
                      {PREFIX}-{checkResult.code}
                    </div>
                    {getName(checkResult.code) && (
                      <div style={{ fontSize:12, color:"#aaa" }}>📦 {getName(checkResult.code)}</div>
                    )}
                  </div>
                  <span style={{ fontSize:10, letterSpacing:3, fontWeight:700, color:st.color, background:st.bg,
                    border:`1px solid ${st.border}`, padding:"4px 10px", borderRadius:4 }}>
                    {st.label}
                  </span>
                </div>

                {/* Partial matches */}
                {checkResult.status === "partial" && checkResult.matches && (
                  <div style={{ marginTop:14 }}>
                    <div style={{ fontSize:10, letterSpacing:2, color:"#666", marginBottom:8 }}>COINCIDENCIAS ENCONTRADAS</div>
                    <div style={{ display:"flex", flexDirection:"column", gap:6 }}>
                      {checkResult.matches.slice(0,12).map(code => {
                        const parts = code.toUpperCase().split(checkResult.code);
                        return (
                          <div key={code} style={{ background:"#1a1a1a", border:"1px solid #2a2a2a", borderRadius:7,
                            padding:"8px 12px", display:"flex", justifyContent:"space-between", alignItems:"center" }}>
                            <div>
                              <span style={{ fontSize:13, fontWeight:600, color:"#e8e8e8", fontFamily:"monospace" }}>
                                {PREFIX}-{parts.map((part, i) => (
                                  <span key={i}>
                                    {i > 0 && <span style={{ background:"#facc15", color:"#111", fontWeight:700, padding:"0 1px", borderRadius:2 }}>{checkResult.code}</span>}
                                    {part}
                                  </span>
                                ))}
                              </span>
                              {getName(code) && <div style={{ fontSize:11, color:"#666", marginTop:2 }}>{getName(code)}</div>}
                            </div>
                            <span style={{ fontSize:10, color:"#f87171", background:"#1e0f0f", border:"1px solid #5c1f1f",
                              padding:"2px 8px", borderRadius:4 }}>EXISTE</span>
                          </div>
                        );
                      })}
                    </div>
                  </div>
                )}

                {/* Available — register button */}
                {checkResult.status === "available" && (
                  <button onClick={() => handleRegister(checkResult.code)}
                    style={{ ...S.btn, marginTop:14, background:"#4ade80", color:"#0b1a0f" }}>
                    ✓ Registrar {PREFIX}-{checkResult.code} como nuevo
                  </button>
                )}
              </div>
            );
          })()}

          {/* Alternatives */}
          {alternatives && (alternatives.results.length > 0 || alternatives.siblings.length > 0) && (
            <div style={S.card}>
              {alternatives.results.length > 0 && (<>
                <div style={{ fontSize:10, letterSpacing:2, color:"#888", marginBottom:10 }}>CÓDIGOS DISPONIBLES SIMILARES</div>
                <div style={{ display:"flex", flexDirection:"column", gap:6, marginBottom:14 }}>
                  {alternatives.results.map(alt => (
                    <div key={alt.code} style={{ background:"#111", border:"1px solid #2a2a2a", borderRadius:7,
                      padding:"8px 12px", display:"flex", justifyContent:"space-between", alignItems:"center" }}>
                      <span style={{ fontSize:13, fontWeight:600, color:"#4ade80", fontFamily:"monospace" }}>{PREFIX}-{alt.code}</span>
                      <button onClick={() => handleRegister(alt.code)}
                        style={{ ...S.btn, padding:"5px 12px", fontSize:11, background:"#4ade80", color:"#0b1a0f" }}>
                        Registrar
                      </button>
                    </div>
                  ))}
                </div>
              </>)}
              {alternatives.siblings.length > 0 && (<>
                <div style={{ fontSize:10, letterSpacing:2, color:"#666", marginBottom:8 }}>FAMILIA EXISTENTE (mismo código base)</div>
                <div style={{ display:"flex", flexWrap:"wrap", gap:6 }}>
                  {alternatives.siblings.map(s => (
                    <span key={s} style={{ background:"#1a1a1a", border:"1px solid #2a2a2a", borderRadius:5,
                      padding:"4px 10px", fontSize:11, color:"#888", fontFamily:"monospace" }}>
                      {PREFIX}-{s}
                    </span>
                  ))}
                </div>
              </>)}
            </div>
          )}

          {/* GENERATE MODE */}
          {mode === "generate" && (<>
            {/* Step 1: search by name */}
            {genStep >= 1 && (
            <div style={S.card}>
              <span style={S.label}>PASO 1 · BUSCAR ARTÍCULO POR NOMBRE</span>
              <div style={{ display:"flex", gap:8 }}>
                <input value={nameQuery} onChange={e => setNameQuery(e.target.value)}
                  onKeyDown={e => e.key==="Enter" && searchByName()}
                  placeholder="Ej: buzo canguro gris" style={S.input} />
                <button onClick={searchByName} style={S.btn}>Buscar</button>
              </div>
            </div>)}

            {/* Step 2: pick from results */}
            {genStep >= 2 && nameMatches && (
            <div style={S.card}>
              <span style={S.label}>PASO 2 · SELECCIONÁ EL ARTÍCULO</span>
              {nameMatches.length === 0
                ? <div style={{ color:"#666", fontSize:13 }}>Sin resultados para "{nameQuery}"</div>
                : <div style={{ display:"flex", flexDirection:"column", gap:6 }}>
                  {nameMatches.map(({ code, name }) => (
                    <div key={code} onClick={() => pickFamily(code)}
                      style={{ background: selectedFamily?.code===code ? "#1a2a1a" : "#111",
                        border:`1px solid ${selectedFamily?.code===code ? "#1a5c30" : "#2a2a2a"}`,
                        borderRadius:7, padding:"10px 14px", cursor:"pointer", transition:"all .15s" }}>
                      <div style={{ fontSize:13, fontWeight:600, color:"#e8e8e8", fontFamily:"monospace" }}>
                        {PREFIX}-{code}
                      </div>
                      <div style={{ fontSize:11, color:"#888", marginTop:2 }}>{name}</div>
                    </div>
                  ))}
                </div>
              }
            </div>)}

            {/* Step 3: color suffix + generate */}
            {genStep >= 3 && selectedFamily && (
            <div style={S.card}>
              <span style={S.label}>PASO 3 · VARIANTE DE COLOR (opcional)</span>
              <div style={{ fontSize:11, color:"#888", marginBottom:10 }}>
                Familia seleccionada: <span style={{ color:"#e8e8e8", fontWeight:600 }}>{PREFIX}-{selectedFamily.code}</span>
              </div>
              {selectedFamily.siblings.length > 0 && (
                <div style={{ marginBottom:12 }}>
                  <div style={{ fontSize:10, letterSpacing:2, color:"#666", marginBottom:6 }}>COLORES YA EXISTENTES EN ESTA FAMILIA</div>
                  <div style={{ display:"flex", flexWrap:"wrap", gap:5 }}>
                    {selectedFamily.siblings.map(s => (
                      <span key={s} style={{ background:"#1a1a1a", border:"1px solid #2a2a2a", borderRadius:5,
                        padding:"3px 9px", fontSize:11, color:"#888", fontFamily:"monospace" }}>
                        {PREFIX}-{s}
                      </span>
                    ))}
                  </div>
                </div>
              )}
              <div style={{ display:"flex", gap:8 }}>
                <input value={colorSuffix} onChange={e => setColorSuffix(e.target.value)}
                  onKeyDown={e => e.key==="Enter" && buildAndGenerate()}
                  placeholder="Ej: ROJO, AZL, etc. (o dejá vacío)" style={S.input} />
                <button onClick={buildAndGenerate} style={S.btn}>Generar</button>
              </div>
            </div>)}

            {/* Generated result */}
            {genResult && (() => {
              const st = genResult.results.length > 0 ? STATUS.available : STATUS.exists;
              return (
                <div style={{ background:st.bg, border:`1px solid ${st.border}`, borderRadius:10, padding:20, marginBottom:14 }}>
                  <div style={{ fontSize:10, letterSpacing:2, color:"#888", marginBottom:8 }}>CÓDIGO GENERADO</div>
                  {genResult.results.length > 0
                    ? <>
                      <div style={{ display:"flex", flexDirection:"column", gap:6 }}>
                        {genResult.results.map(alt => (
                          <div key={alt.code} style={{ background:"#111", border:"1px solid #1a5c30", borderRadius:7,
                            padding:"8px 12px", display:"flex", justifyContent:"space-between", alignItems:"center" }}>
                            <span style={{ fontSize:14, fontWeight:700, color:"#4ade80", fontFamily:"monospace" }}>{PREFIX}-{alt.code}</span>
                            <button onClick={() => handleRegister(alt.code)}
                              style={{ ...S.btn, padding:"5px 12px", fontSize:11, background:"#4ade80", color:"#0b1a0f" }}>
                              Registrar
                            </button>
                          </div>
                        ))}
                      </div>
                    </>
                    : <div style={{ color:"#f87171", fontSize:13 }}>No se encontraron códigos disponibles para "{genResult.base}"</div>
                  }
                </div>
              );
            })()}
          </>)}
        </>)}

        {/* ── BUSCAR ARTÍCULOS ── */}
        {tab === "search" && (
          <div>
            <div style={S.card}>
              <span style={S.label}>BUSCAR EN MARCA {PREFIX} · {CODES.length} artículos</span>
              <input value={searchTerm} onChange={e => setSearchTerm(e.target.value)}
                placeholder="Código o nombre del artículo..." autoFocus style={S.input} />
            </div>
            <div style={{ display:"flex", flexDirection:"column", gap:6 }}>
              {filteredCodes.map(code => {
                const name = getName(code) || "";
                const q = searchTerm.toLowerCase();
                const highlight = (text) => {
                  if (!q || !text.toLowerCase().includes(q)) return text;
                  const parts = text.split(new RegExp(`(${q})`, "gi"));
                  return parts.map((p, i) => i % 2 === 1
                    ? <span key={i} style={{ background:"#facc15", color:"#111", fontWeight:700, borderRadius:2, padding:"0 1px" }}>{p}</span>
                    : p);
                };
                return (
                  <div key={code} style={{ background:"#1a1a1a", border:"1px solid #2a2a2a", borderRadius:8,
                    padding:"10px 14px", display:"flex", justifyContent:"space-between", alignItems:"center" }}>
                    <div>
                      <div style={{ fontSize:13, fontWeight:600, color:"#e8e8e8", fontFamily:"monospace" }}>
                        {PREFIX}-{highlight(code)}
                      </div>
                      {name && <div style={{ fontSize:11, color:"#666", marginTop:2 }}>{highlight(name)}</div>}
                    </div>
                    <span style={{ fontSize:10, color:"#f87171", background:"#1e0f0f", border:"1px solid #5c1f1f",
                      padding:"2px 8px", borderRadius:4, whiteSpace:"nowrap" }}>YA EXISTE</span>
                  </div>
                );
              })}
              {filteredCodes.length === 0 && (
                <div style={{ color:"#555", fontSize:13, padding:20, textAlign:"center" }}>
                  Sin resultados para "{searchTerm}"
                </div>
              )}
              {!searchTerm && CODES.length > 80 && (
                <div style={{ color:"#555", fontSize:11, textAlign:"center", padding:10 }}>
                  Mostrando 80 de {CODES.length} — buscá para filtrar
                </div>
              )}
            </div>
          </div>
        )}

        {/* ── MARCAS ── */}
        {tab === "brands" && (
          <div>
            <div style={S.card}>
              <span style={S.label}>SELECCIONÁ UNA MARCA</span>
              <input value={brandSearch} onChange={e => setBrandSearch(e.target.value)}
                placeholder="Filtrar por prefijo (ej: 221)..." autoFocus style={S.input} />
            </div>
            <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill, minmax(180px, 1fr))", gap:8 }}>
              {filteredBrands.map(([prefix, d]) => {
                const isActive = prefix === activeBrand;
                return (
                  <div key={prefix}
                    onClick={() => { setActiveBrand(prefix); resetAll(); setTab("check"); }}
                    style={{ background: isActive ? "#1a2a1a" : "#1a1a1a",
                      border:`1px solid ${isActive ? "#1a5c30" : "#2a2a2a"}`,
                      borderRadius:9, padding:"12px 14px", cursor:"pointer", transition:"all .15s" }}>
                    <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:4 }}>
                      <span style={{ fontSize:18, fontWeight:700, color: isActive ? "#4ade80" : "#e8e8e8", fontFamily:"monospace" }}>
                        {prefix}
                      </span>
                      {isActive && (
                        <span style={{ fontSize:9, background:"#0b1a0f", border:"1px solid #1a5c30",
                          color:"#4ade80", borderRadius:3, padding:"1px 5px", letterSpacing:1 }}>ACTIVA</span>
                      )}
                    </div>
                    <div style={{ fontSize:11, color:"#555" }}>{d.codes.length} artículos</div>
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {/* ── SESIÓN ── */}
        {tab === "list" && (
          <div>
            {newCodes.length === 0
              ? <div style={{ color:"#555", fontSize:13, padding:40, textAlign:"center" }}>
                  Todavía no registraste códigos nuevos en esta sesión.
                </div>
              : <>
                <div style={{ fontSize:11, color:"#555", marginBottom:14 }}>
                  {newCodes.length} código{newCodes.length !== 1 ? "s" : ""} registrado{newCodes.length !== 1 ? "s" : ""} esta sesión
                </div>
                <div style={{ display:"flex", flexDirection:"column", gap:6 }}>
                  {newCodes.map((item, i) => (
                    <div key={i} style={{ background:"#1a1a1a", border:"1px solid #1a5c30", borderRadius:8,
                      padding:"10px 14px", display:"flex", justifyContent:"space-between", alignItems:"center" }}>
                      <span style={{ fontFamily:"monospace", fontSize:14, fontWeight:600, color:"#4ade80" }}>
                        {item.full}
                      </span>
                      <span style={{ fontSize:10, color:"#4ade80", background:"#0b1a0f",
                        border:"1px solid #1a5c30", padding:"2px 8px", borderRadius:4 }}>NUEVO</span>
                    </div>
                  ))}
                </div>
                <button onClick={() => {
                  const text = newCodes.map(c => c.full).join("\n");
                  navigator.clipboard?.writeText(text).then(() => showToast("✓ Copiado al portapapeles"));
                }} style={{ ...S.btn, marginTop:16, width:"100%" }}>
                  Copiar todos al portapapeles
                </button>
              </>
            }
          </div>
        )}

      </div>

      {toast && (
        <div style={{ position:"fixed", bottom:20, left:"50%", transform:"translateX(-50%)",
          background:"#222", color:"#e8e8e8", border:"1px solid #404040", padding:"9px 20px",
          borderRadius:8, fontSize:12, fontFamily:"'Inter',sans-serif",
          boxShadow:"0 4px 20px rgba(0,0,0,.6)", zIndex:1000, whiteSpace:"nowrap" }}>
          {toast}
        </div>
      )}
      <style>{`
  @keyframes fi{from{opacity:0;transform:translate(-50%,8px)}to{opacity:1;transform:translate(-50%,0)}}
  input::placeholder{color:#555}
  *{font-family:'Inter',sans-serif!important}
`}</style>
    </div>
  );
}